example.programlisting:
...
route {
    if (is_method("INVITE") && !has_totag()) {
        if (sst_check("0", "0") == -1) {
            # Session interval too small - send 422
            append_hf("Min-SE: $var(sst_min_se)\r\n");
            sl_send_reply(422, "Session Interval Too Small");
            exit;
        }
        xlog("L_DBG", "SST OK: interval=$var(sst_interval)\n");
    }
}
...

...
onreply_route[sst_reply] {
    if ($rs == "200" && is_method("INVITE")) {
        sst_update("0", "0", "uas");
        append_hf("Session-Expires: $var(sst_session_expires)\r\n");
        append_hf("Min-SE: $var(sst_min_se)\r\n");
    }
}
...

...
route[reload] {
    if (sst_reload()) {
        xlog("L_INFO", "SST policies reloaded: $var(sst_reload_count) entries\n");
    }
}
...
